use fastly::http::{header, Method, StatusCode};
use fastly::{mime, Error, Request, Response};

const BACKEND_API: &str = "api_backend";
const BACKEND_STATIC: &str = "static_backend";
const BACKEND_AUTH: &str = "auth_backend";

#[fastly::main]
fn main(mut req: Request) -> Result<Response, Error> {
    let path = req.get_path();
    let method = req.get_method();

    match (method, path) {
        (_, path) if path.starts_with("/api/") => {
            handle_api_request(req)
        }
        (_, path) if path.starts_with("/auth/") => {
            handle_auth_request(req)
        }
        (_, path) if path.starts_with("/static/") => {
            handle_static_request(req)
        }
        (&Method::GET, "/") => {
            Ok(Response::from_status(StatusCode::OK)
                .with_content_type(mime::TEXT_HTML_UTF_8)
                .with_body("<h1>Fastly Compute@Edge Routing Service</h1>"))
        }
        _ => {
            Ok(Response::from_status(StatusCode::NOT_FOUND)
                .with_body("Not Found"))
        }
    }
}

fn handle_api_request(mut req: Request) -> Result<Response, Error> {
    req.set_header(header::HOST, "api.example.com");
    req.set_header("X-Forwarded-Proto", "https");
    
    let backend_response = req.send(BACKEND_API)?;
    
    Ok(backend_response)
}

fn handle_auth_request(mut req: Request) -> Result<Response, Error> {
    req.set_header(header::HOST, "auth.example.com");
    req.set_header("X-Forwarded-Proto", "https");
    
    let backend_response = req.send(BACKEND_AUTH)?;
    
    Ok(backend_response)
}

fn handle_static_request(mut req: Request) -> Result<Response, Error> {
    req.set_header(header::HOST, "static.example.com");
    req.set_header("X-Forwarded-Proto", "https");
    req.set_header(header::CACHE_CONTROL, "public, max-age=3600");
    
    let mut backend_response = req.send(BACKEND_STATIC)?;
    
    if backend_response.get_status().is_success() {
        backend_response.set_header(header::CACHE_CONTROL, "public, max-age=86400");
    }
    
    Ok(backend_response)
}